/**
 * Creates gRPC metadata from HTTP request headers.
 * Forwards known headers, custom headers, and allows explicit header injection.
 */
function createGrpcMetadataFromHttpHeaders(httpHeaders, additionalMetadata = {}) {
  const metadata = new grpc.Metadata();

  // Forward known/standard headers
  for (const headerName of FORWARDED_HEADERS) {
    const headerValue = httpHeaders[headerName];
    if (headerValue !== undefined && headerValue !== null) {
      if (Array.isArray(headerValue)) {
        headerValue.forEach((val) => metadata.add(headerName, val));
      } else {
        metadata.add(headerName, String(headerValue));
      }
    }
  }

  // Forward any custom headers with the designated prefix
  for (const [key, value] of Object.entries(httpHeaders)) {
    const lowerKey = key.toLowerCase();
    if (
      lowerKey.startsWith(CUSTOM_HEADER_PREFIX) &&
      !FORWARDED_HEADERS.includes(lowerKey)
    ) {
      if (Array.isArray(value)) {
        value.forEach((val) => metadata.add(lowerKey, val));
      } else {
        metadata.add(lowerKey, String(value));
      }
    }
  }

  // Add any additional metadata entries provided programmatically
  for (const [key, value] of Object.entries(additionalMetadata)) {
    if (Array.isArray(value)) {
      value.forEach((val) => metadata.add(key, val));
    } else {
      metadata.add(key, String(value));
    }
  }

  // Always add gateway identification metadata
  metadata.add('x-gateway-timestamp', new Date().toISOString());
  metadata.add('x-forwarded-by', 'api-gateway');

  return metadata;
}

